drop extension if exists "pg_net";


  create table "public"."clothes" (
    "id" character varying not null,
    "created_at" timestamp with time zone not null default now(),
    "name" text,
    "category" text,
    "stars" text,
    "tags" text,
    "scores" jsonb,
    "game_id" text
      );


alter table "public"."clothes" enable row level security;


  create table "public"."pending_clothes" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "name" text
      );



  create table "public"."profiles" (
    "id" uuid not null,
    "email" text,
    "nickname" text,
    "role" text default 'user'::text,
    "quota" integer default 30,
    "updated_at" timestamp with time zone default now()
      );


alter table "public"."profiles" enable row level security;


  create table "public"."stages" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "name" text,
    "weights" jsonb
      );



  create table "public"."user_quotas" (
    "user_id" uuid not null,
    "free_count" integer default 20
      );


alter table "public"."user_quotas" enable row level security;


  create table "public"."user_wardrobes" (
    "id" uuid not null default gen_random_uuid(),
    "created_at" timestamp with time zone not null default now(),
    "user_id" uuid default gen_random_uuid(),
    "owned_clothes" jsonb
      );


alter table "public"."user_wardrobes" enable row level security;

CREATE UNIQUE INDEX clothes_name_category_unique ON public.clothes USING btree (name, category);

CREATE UNIQUE INDEX clothes_pkey ON public.clothes USING btree (id);

CREATE UNIQUE INDEX pending_clothes_pkey ON public.pending_clothes USING btree (id);

CREATE UNIQUE INDEX profiles_pkey ON public.profiles USING btree (id);

CREATE UNIQUE INDEX stages_name_key ON public.stages USING btree (name);

CREATE UNIQUE INDEX stages_pkey ON public.stages USING btree (id);

CREATE UNIQUE INDEX user_quotas_pkey ON public.user_quotas USING btree (user_id);

CREATE UNIQUE INDEX user_wardrobes_pkey ON public.user_wardrobes USING btree (id);

CREATE UNIQUE INDEX user_wardrobes_user_id_key ON public.user_wardrobes USING btree (user_id);

alter table "public"."clothes" add constraint "clothes_pkey" PRIMARY KEY using index "clothes_pkey";

alter table "public"."pending_clothes" add constraint "pending_clothes_pkey" PRIMARY KEY using index "pending_clothes_pkey";

alter table "public"."profiles" add constraint "profiles_pkey" PRIMARY KEY using index "profiles_pkey";

alter table "public"."stages" add constraint "stages_pkey" PRIMARY KEY using index "stages_pkey";

alter table "public"."user_quotas" add constraint "user_quotas_pkey" PRIMARY KEY using index "user_quotas_pkey";

alter table "public"."user_wardrobes" add constraint "user_wardrobes_pkey" PRIMARY KEY using index "user_wardrobes_pkey";

alter table "public"."clothes" add constraint "clothes_name_category_unique" UNIQUE using index "clothes_name_category_unique";

alter table "public"."profiles" add constraint "profiles_id_fkey" FOREIGN KEY (id) REFERENCES auth.users(id) not valid;

alter table "public"."profiles" validate constraint "profiles_id_fkey";

alter table "public"."stages" add constraint "stages_name_key" UNIQUE using index "stages_name_key";

alter table "public"."user_quotas" add constraint "user_quotas_user_id_fkey" FOREIGN KEY (user_id) REFERENCES auth.users(id) not valid;

alter table "public"."user_quotas" validate constraint "user_quotas_user_id_fkey";

alter table "public"."user_wardrobes" add constraint "user_wardrobes_user_id_fkey" FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE not valid;

alter table "public"."user_wardrobes" validate constraint "user_wardrobes_user_id_fkey";

alter table "public"."user_wardrobes" add constraint "user_wardrobes_user_id_key" UNIQUE using index "user_wardrobes_user_id_key";

set check_function_bodies = off;

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  INSERT INTO public.profiles (id, email, nickname, role, quota)
  VALUES (new.id, new.email, split_part(new.email, '@', 1), 'user', 30);
  RETURN new;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user_quota()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  INSERT INTO public.user_quotas (user_id, free_count)
  VALUES (new.id, 30); -- 新用户默认给 20 次
  RETURN new;
END;
$function$
;

