  create policy "Enable read access for all users"
  on "public"."clothes"
  as permissive
  for select
  to public
using (true);



  create policy "仅管理员可操作图鉴"
  on "public"."clothes"
  as permissive
  for all
  to authenticated
using ((EXISTS ( SELECT 1
   FROM public.profiles
  WHERE ((profiles.id = auth.uid()) AND (profiles.role = 'admin'::text)))));



  create policy "管理员权限"
  on "public"."clothes"
  as permissive
  for all
  to authenticated
using ((auth.email() = '2230909994@qq.com'::text))
with check ((auth.email() = '2230909994@qq.com'::text));



  create policy "用户可以查看自己的画像"
  on "public"."profiles"
  as permissive
  for select
  to public
using ((auth.uid() = id));



  create policy "允许用户查看自己的额度"
  on "public"."user_quotas"
  as permissive
  for select
  to public
using ((auth.uid() = user_id));



  create policy "允许用户操作自己的衣柜"
  on "public"."user_wardrobes"
  as permissive
  for all
  to authenticated
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));



  create policy "用户只能操作自己的衣柜"
  on "public"."user_wardrobes"
  as permissive
  for all
  to authenticated
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));


CREATE TRIGGER on_auth_user_created_profile AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();


